var e=[{id:`L2_1`,type:`dialog`,speaker:`PUPPET_BLIND_CLB_003`,text:{KOREA:`나는 세상에 희망을 전파하기 위해 세 번 내려왔어. 그런데 설마, 노래가 아닌 새로운 희망을 엿보게 될 줄이야! 이게 바로 운명이라는 거겠지?`,JPN:`私は世界を希望で満たすために3回も降りてきたんだ。でも、まさかここで歌じゃないものに希望を見つけることになるとは！　これが運命ってやつなんだろうね？`,ENG:`I descended three times to spread hope across the world.  But I never thought I'd come across a new kind of hope that wasn't music! This must be fate.`,TWN:`I descended three times to spread hope across the world.  But I never thought I'd come across a new kind of hope that wasn't music! This must be fate.`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PUPPET_BLIND_CLB_003`,face:`UNIT_LAUGH`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`PUPPET_BLIND_CLB_003`,text:{KOREA:`앞으로도 계속 날 지켜봐 줘야 해? 물론, 엔딩콜도 기다려주고!`,JPN:`これからもずっとわたしのこと見守ってよ？　エンディングコールまで待ってくれるのもね！`,ENG:`Keep watching over me! And of course, stay for the secret ending as well!`,TWN:`Keep watching over me! And of course, stay for the secret ending as well!`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PUPPET_BLIND_CLB_003`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};